for si in root.findall('a:si',ns):
 texts=[]
 for t in si.iter('{http://schemas.openxmlformats.org/spreadsheetml/2006/main}t'):
  texts.append(t.text or '')
 ss.append(''.join(texts))

def col_to_num(cell):
 m=re.match(r'([A-Z]+)',cell)
 n=0
 for ch in m.group(1): n=n*26+ord(ch)-64
 return n

def cellval(c):
 t=c.attrib.get('t')
 v=c.find('a:v',ns)
 if t=='s':
  return ss[int(v.text)] if v is not None and v.text is not None else ''
 if t=='inlineStr':
  texts=[x.text or '' for x in c.iter('{http://schemas.openxmlformats.org/spreadsheetml/2006/main}t')]
  return ''.join(texts)
 return v.text if v is not None else None
sheet=ET.fromstring(z.read('xl/worksheets/sheet1.xml'))
rows=[]
for row in sheet.findall('.//a:sheetData/a:row',ns):
 vals={col_to_num(c.attrib['r']): cellval(c) for c in row.findall('a:c',ns)}
 maxcol=max(vals) if vals else 0
 rows.append([vals.get(i) for i in range(1,maxcol+1)])
